function resolvePath(baseDir: string, target: string): string {
  if (!target) return baseDir;
  if (path.isAbsolute(target)) return target;  // absolute paths allowed
  return path.join(baseDir, target);
}

export function extractHookToken(req: IncomingMessage, url: URL): string | undefined {
  const auth = typeof req.headers.authorization === 'string' ? req.headers.authorization.trim() : '';
  if (auth.toLowerCase().startsWith('bearer ')) {
    const token = auth.slice(7).trim();
    if (token) return token;
  }
  const headerToken = typeof req.headers['x-clawdbot-token'] === 'string'
    ? req.headers['x-clawdbot-token'].trim() : '';
  if (headerToken) return headerToken;
  const queryToken = url.searchParams.get('token');  // <-- token in URL
  if (queryToken) return queryToken.trim();
  return undefined;
}

